import {
  Button,
  Form,
  Select,
  TableColumnProps,
  Badge,
  Input,
  Message,
  TreeSelect,
  Popover,
  Cascader,
  Upload,
  Table,
  Modal,
  Grid,
  Tooltip,
} from '@arco-design/web-react'
import {
  IconExport,
  IconFile,
  IconImport,
  IconInfoCircle,
  IconLoading,
  IconPlus,
  IconUpload,
} from '@arco-design/web-react/icon'
import { renderEllipsisText } from '@common/components/EllipsisText'
import ListFilterForm from '@common/components/ListFilterForm'
import PageWrapper from '@common/components/PageWrapper'
import UnifiedTableStyle from '@common/components/UnifiedTableStyle'
import { useCallback, useEffect, useRef, useState } from 'react'
import {
  getCycleIdAndName,
  getUserList,
  getRecursiveNormalTree as getOrgTreeRecursion,
  getUserTableHeaderConfig,
  uploadFile,
  importKpiListRequest,
  importMonthlyKpiListRequest,
  downloadTemplateRequest,
  downloadMonthlyTemplateRequest,
} from '@/service'
import { LanguageEnum } from '@common/constants/language.ts'
import useLanguage from '@common/hooks/useLanguage.ts'
import {
  PROJECT_RELEASE_STATUS_TEXTS,
  STATUS_COLOR,
} from '@/constants/project.ts'
import RowActionBtns from '@/pages/StrategicKpis/KpisManagement/components/RowActionBtns'
import { useLocation, useNavigate, useParams } from 'react-router-dom'
import TextContentNotification from '@/pages/StrategicKpis/KpisManagement/components/TextContentNotification/TextContentNotification'
import ActualValueModal from '@/pages/StrategicKpis/KpisManagement/KpiDetail/components/ActualValueModal/ActualValueModal.tsx'
import {
  deleteKpiRequest,
  exportKpiListRequest,
  getKpiList,
} from '@/service/apis/kpis.ts'
import { useTranslation } from 'react-i18next'
import useLocaleTranslation from '@common/hooks/useLocaleTranslation'
import { isReadServerTextData } from '@common/constants/env'
import dayjs from 'dayjs'
import './style/index.less'
import { downloadFile, getYearRange, isInSequence } from '@/utils/tools.ts'
import { useRequest, useLocalStorageState, useSetState } from 'ahooks'
import { getLanguage } from '@common/utils/localStorage.ts'
import { KpiPermissionEnum } from '@/constants/permission'
import useCheckPermission from '@common/hooks/useCheckPermission'
import { RootState } from '@/store'
import { useSelector } from 'react-redux'
import { DashboardState } from '@/store/dashboard.ts'
import _ from 'lodash'
import { roundDown } from '@/utils/strategicKpis'
import PieChart from './components/PieChart/PieChart'
import ViewSwitch from '@common/components/ViewSwitch'
import {
  getMailString,
  jumpToDetailsPage,
  transformData,
  permissionJudgment,
  underline,
} from '@/utils/tools.ts'
import { userViewStorageKey } from '@common/constants/localStorageKey'
import useKpiInfo from './hooks/useKpi'
import { kpiSearchState, kpiSearchInitData } from '@/store/kpi.ts'
import {
  strategyApiTypeEnum,
  measurementTypeEnum,
  kpiImportTypeEnum,
  measurementMechanismEnum,
} from '@/constants/strategicKpis'
import { converTimeFormat } from '@/utils/processActivitiesTime'
import { TableBizType } from '@common/constants/userHead'
import PopSetting from '@common/components/PopSetting'
import { getDaysAgo, cycleClosed } from '@/utils/tools'
import { DashboardTypeEnum } from '@/constants/dashboard'
import IconCloseCircle from '@/assets/images/icon/closeCircle.svg?react'
import IconExcel from '@/assets/images/icon/IconExcel.svg?react'
import classNames from 'classnames'
import useDebouncedPromise from '@common/hooks/useDebouncedPromise.ts'
import axios from 'axios'
import { File_UPLOAD_TYPE } from '@common/constants/uploadTypes.ts'
import OptionSelectModal from '@common/components/OptionSelectModal'
import ManualInput from '@/assets/images/icon/manualInput.svg?react'
import KPIAiIcon from '@/assets/images/icon/kpiAi-icon.svg?react'
const FormItem = Form.Item
const Row = Grid.Row
const Col = Grid.Col

const StrategicKpis = () => {
  const { t } = isReadServerTextData
    ? useLocaleTranslation()
    : useTranslation(['common', 'kpis', 'project', 'historyLog'])
  const tableRef = useRef(null)
  const navigate = useNavigate()
  const { isFromDashboard } = useParams()
  const lang = useLanguage()
  const location = useLocation()
  const { state } = location
  const [tableData, setTableData] = useState([])
  const [tableTotal, setTableTotal] = useState(0)
  const [cycleList, setCycleList] = useState([])
  const [deleteNotificationVisible, setDeleteNotificationVisible] =
    useState(false)
  const [actualValueModalVisible, setActualValueModalVisible] = useState(false)
  const [currentDeleRowId, setCurrentDeleRowId] = useState(null)
  const [kpiInfoId, setKpiInfoId] = useState(null)
  const [selectCycleId, setSelectCycleId] = useState('id')
  const isLanguageAR = getLanguage() === LanguageEnum.AR
  const [userList, setUserList] = useState([])
  const [importTemplateType, setImportTemplateType] = useState(0)

  const checkPermission = useCheckPermission()
  const canKpiAdd = checkPermission(KpiPermissionEnum.ADD)
  const canAdminUserView = checkPermission(KpiPermissionEnum.KpiAdminUserView)
  const headUserView = checkPermission(KpiPermissionEnum.KpiHeadUserView)
  const canHeadUserView =
    canAdminUserView && headUserView ? false : headUserView
  const formRef = useRef(null)
  const [departmentData, setDepartmentData] = useState<any>([])
  const [isUser, setIsUser] = useLocalStorageState<any>(userViewStorageKey, {
    defaultValue: false,
  })
  const { cycleId: dashBoardSelectedCycleId } = useSelector<
    RootState,
    DashboardState
  >((state) => state.dashboard)
  const [importSuccessfullyUpdate, setImportSuccessfullyUpdate] = useState(0)

  const { kpiSearch, setKpiSearchInfo } = useKpiInfo()
  const [kpiFilterParams, setKpiFilterParams] = useSetState<kpiSearchState>({
    ...kpiSearch,
  })

  const [optionSelectVisible, setOptionSelectVisible] = useState(false)

  const strategyApiTypeObject = {
    '0': t('kpis:informationTypes.inStats'),
    '1': t('kpis:informationTypes.exStats'),
  }

  const kpiTypeEnum = {
    1: t('kpis:strategicKpi'),
    2: t('kpis:operationalKpi'),
    3: t('kpis:processKpi'),
    4: t('kpis:enablerKpi'),
  }
  const strategyApiTypeOptions = [
    {
      label: t('kpis:informationTypes.inStats'),
      value: strategyApiTypeEnum['Counted in Stats'],
    },
    {
      label: t('kpis:informationTypes.exStats'),
      value: strategyApiTypeEnum['Excluded from Stats'],
    },
  ]

  const kpiTypeList = [
    {
      label: t('kpis:strategicKpi'),
      value: 1,
    },
    {
      label: t('kpis:operationalKpi'),
      value: 2,
    },
    {
      label: t('kpis:processKpi'),
      value: 3,
    },
    {
      label: t('kpis:enablerKpi'),
      value: 4,
    },
  ]

  // 查询用户列表
  const { run: getAllUserList } = useRequest(getUserList, {
    manual: true,
    onSuccess(data: any, params) {
      const userOptions = data.map((item) => ({
        label: isLanguageAR
          ? `${item.fullNameAr}(${getMailString(item.mail)})`
          : `${item.fullName}(${getMailString(item.mail)})`,
        value: item.userId,
      }))
      setUserList(userOptions || [])
    },
    onError(e, params) {
      console.log({ e, params })
    },
  })
  //table change 回调
  const tableChange = (pagination, sorter, filters) => {
    setKpiSearchInfo({
      ...kpiSearch,
      pageNum: pagination.current,
      pageSize: pagination.pageSize,
    })
    setKpiFilterParams({
      pageNum: pagination.current,
      pageSize: pagination.pageSize,
    })
  }

  //删除按钮点击
  const debouncedKpiDelete = useDebouncedPromise(deleteKpiRequest, 500)
  const { loading: deleteLoading, runAsync: runKpiDelete } = useRequest(
    debouncedKpiDelete,
    {
      manual: true,
      onSuccess: () => {
        Message.success(t('common:message.deleteSuccessfully'))
        const tableData = tableRef.current?.getData()
        const tableDataNo = tableData[0]['no']
        const deleteDataFlag = isInSequence(tableDataNo, tableData)
        if (deleteDataFlag && kpiSearch.pageNum > 1) {
          const nowPage = Number(kpiSearch.pageNum - 1)
          setKpiSearchInfo({ ...kpiSearch, pageNum: nowPage })
          setKpiFilterParams({ pageNum: nowPage })
        }
        // tableRef.current.refresh()
      },
    },
  )

  const deleteHandle = (id) => {
    setDeleteNotificationVisible(false)
    runKpiDelete(currentDeleRowId)
  }

  const { run: exportKpi, loading: exportLoading } = useRequest(
    exportKpiListRequest,
    {
      manual: true,
      onSuccess: (res: any) => {
        if (res) {
          const fileName = `${t('kpis:name')}-${dayjs().valueOf()}.xlsx`
          downloadFile(res.data, fileName)
        }
      },
    },
  )
  //导出按钮点击回调
  const exportHandler = () => {
    exportKpi({
      pageNum: 1,
      pageSize: tableTotal ?? 20,
      cycleId: kpiSearch.cycleId || '',
      responsiblePerson: kpiSearch.responsiblePerson || '',
      keyword: kpiSearch.keyword || '',
      type: kpiSearch.type,
      orgId: kpiSearch.orgId || '',
      userView: isUser,
      year: kpiSearch.year || '',
      measurementCycle: kpiSearch.measurementCycle || '',
      kpiType: kpiSearch.kpiType || '',
    })
  }
  //获取表格数据
  const getList = useCallback(
    (
      pageParams: { pageNum: number; pageSize: number } = {
        pageNum: kpiSearch.pageNum,
        pageSize: kpiSearch.pageSize,
      },
    ) => {
      if (selectCycleId === 'id') {
        return Promise.resolve({
          list: [],
          total: 0,
          pageNum: kpiSearch.pageNum,
          pageSize: kpiSearch.pageSize,
        })
      }
      let result = new Promise((resolve, reject) => {
        getKpiList({
          keyword: kpiSearch.keyword,
          type: kpiSearch.type,
          measurementCycle: kpiSearch.measurementCycle,
          cycleId: kpiSearch.cycleId || undefined,
          year: kpiSearch.year || undefined,
          responsiblePerson: kpiSearch.responsiblePerson,
          userView: isUser,
          orgId: kpiSearch.orgId,
          kpiType: kpiSearch.kpiType,
          ...pageParams,
          pageNum: kpiSearch.pageNum,
        }).then((res: any) => {
          const kpiListData = res?.list || []
          let temp = kpiListData.map((item) => ({
            ...item,
            responsiblePersonList: item.responsiblePersonList
              ?.map((v) => {
                return lang == LanguageEnum.EN ? v.name : v.nameAr
              })
              .join(','),
            responsiblePersonId: item.responsiblePerson,
            kpiName: isLanguageAR ? item.kpiNameAr : item.kpiName,
            objectName: isLanguageAR ? item.objectNameAr : item.objectName,
          }))
          setTableData(temp)
          setTableTotal(res.total)
          resolve({
            ...res,
            list: temp,
            pageNum: kpiSearch.pageNum,
            pageSize: kpiSearch.pageSize,
          })
        })
      })
      return result
    },
    [
      location,
      kpiFilterParams,
      deleteLoading,
      selectCycleId,
      importSuccessfullyUpdate,
    ],
  )
  const addBtnHandle = () => {
    setOptionSelectVisible(true)
    // navigate('/strategic-kpis/kpisManagement/add')
  }

  const getMeasurementCycleDefault = () => {
    if (
      kpiSearch.measurementCycle &&
      kpiSearch.measurementCycle !== undefined
    ) {
      if (
        kpiSearch.measurementCycle == 'H1' ||
        kpiSearch.measurementCycle == 'H2'
      ) {
        return ['semiAnnual', `${kpiSearch.measurementCycle}`]
      }
      if (
        kpiSearch.measurementCycle == 'Q1' ||
        kpiSearch.measurementCycle == 'Q2' ||
        kpiSearch.measurementCycle == 'Q3' ||
        kpiSearch.measurementCycle == 'Q4'
      ) {
        return ['quarterly', `${kpiSearch.measurementCycle}`]
      }
      if (kpiSearch.measurementCycle == 'ANNUAL') {
        return ['annual', `${kpiSearch.measurementCycle}`]
      }
      const monthValues = [
        'jan',
        'feb',
        'mar',
        'apr',
        'may',
        'jun',
        'jul',
        'aug',
        'sep',
        'oct',
        'nov',
        'dec',
      ]
      if (monthValues.includes(kpiSearch.measurementCycle)) {
        return ['monthly', `${kpiSearch.measurementCycle}`]
      }
      return []
    }
  }
  useEffect(() => {
    formRef?.current?.setFormItemValue('keyword', kpiSearch.keyword || '')
    formRef?.current?.setFormItemValue(
      'userId',
      kpiSearch.responsiblePerson || undefined,
    )
    formRef?.current?.setFormItemValue('orgId', kpiSearch.orgId || undefined)
    formRef?.current?.setFormItemValue('type', kpiSearch.type || undefined)
    formRef?.current?.setFormItemValue(
      'kpiType',
      kpiSearch.kpiType || undefined,
    )
    formRef?.current?.setFormItemValue(
      'measurementCycle',
      getMeasurementCycleDefault() || undefined,
    )

    getAllUserList({ pageNum: 1, pageSize: 9999 })
    getCycleIdAndName().then((res: any) => {
      if (res?.length > 0) {
        const getCycleYearRange = res.map((item) => ({
          year: getYearRange(
            converTimeFormat(item?.startDate),
            converTimeFormat(item?.endDate),
          ),
        }))
        let temp = res.map((item, index) => ({
          label: lang == LanguageEnum.EN ? item.cycleName : item.cycleNameAr,
          value: item.id,
          children: getCycleYearRange[index].year.map((v) => ({
            label: v,
            value: v,
          })),
        }))

        setCycleList(temp) //cycle and year
        const nowCycleId =
          isFromDashboard === undefined
            ? _.isEmpty(kpiSearch.cycleId) || _.isEmpty(location.state)
              ? temp[0]?.value
              : kpiSearch.cycleId
            : dashBoardSelectedCycleId
        const getNowCycleAndYearObj = temp.filter((m) => m.value === nowCycleId)
        const currentYear = new Date().getFullYear()
        const cycleAllYears = getNowCycleAndYearObj[0]?.children.map(
          (m) => m.value,
        )
        const selectYear = cycleAllYears.includes(String(currentYear))
          ? String(currentYear)
          : String(cycleAllYears[0])
        formRef?.current?.setFormItemValue('cycleIdAndYear', [
          nowCycleId,
          selectYear,
        ])
        setKpiSearchInfo({
          ...kpiSearch,
          cycleId: nowCycleId,
          year: selectYear,
        })
        setKpiFilterParams({ cycleId: nowCycleId, year: selectYear })
        setSelectCycleId(nowCycleId)

        if (isFromDashboard) {
          formRef?.current?.setFormItemValue('keyword', '')
          formRef?.current?.setFormItemValue('orgId', undefined)
          formRef?.current?.setFormItemValue('userId', undefined)
          formRef?.current?.setFormItemValue('type', undefined)
          formRef?.current?.setFormItemValue('measurementCycle', undefined)
          const dashboardType = location?.state?.dashboardType
          if (dashboardType === DashboardTypeEnum.User) {
            setIsUser(true)
          } else if (dashboardType === DashboardTypeEnum.Admin) {
            setIsUser(false)
          }
          setKpiSearchInfo({
            ...kpiSearch,
            cycleId: nowCycleId,
            year: selectYear,
            keyword: '',
          })
          setKpiFilterParams({
            ...kpiSearch,
            cycleId: nowCycleId,
            year: selectYear,
            keyword: '',
          })
        }
        //因为dashboard的state也是空
        if (_.isEmpty(state) && isFromDashboard === undefined) {
          setKpiSearchInfo({
            ...kpiSearch,
            cycleId: nowCycleId,
            year: selectYear,
          })
          setKpiFilterParams({
            ...kpiSearch,
            cycleId: nowCycleId,
            year: selectYear,
          })
          formRef?.current?.setFormItemValue('measurementCycle', undefined)
          formRef?.current?.setFormItemValue('keyword', '')
          formRef?.current?.setFormItemValue('userId', undefined)
          formRef?.current?.setFormItemValue('orgId', undefined)
          formRef?.current?.setFormItemValue('type', undefined)
        }
        getOrgTree({ cycleId: nowCycleId })
      }
    })
  }, [])

  const measurementTypesEnum = {
    0: t('activities:increasingBetter'),
    1: t('activities:decreasingBetter'),
  }
  const getProgressDetailRate = (record) => {
    const progress = +record.completionOfDate.toFixed(2)
    const actualOfDate = +record.actualOfDate.toFixed(2)
    const targetOfDate = +record.targetOfDate.toFixed(2)
    const measurementMechanism = record?.measurementMechanism
    const unitType = record?.measurementUnit
    const type = record?.type
    const formulas = record?.formulas
    const averageOfDate = +record.averageOfDate.toFixed(2)

    return (
      <Popover
        content={
          measurementMechanism == measurementMechanismEnum['duration'] ? (
            ''
          ) : (
            <div
              style={{
                display: 'flex',
                flexDirection: 'column',
                padding: '10px',
              }}
            >
              <p style={{ display: 'inline-flex', gap: '10px' }}>
                <span>{t('activities:columns.avtual')}</span>:
                <span>{actualOfDate}</span>
              </p>
              <p style={{ display: 'inline-flex', gap: '10px' }}>
                <span>{t('activities:columns.target')}</span>:
                <span>
                  {type == strategyApiTypeEnum['Excluded from Stats']
                    ? '--'
                    : targetOfDate}
                </span>
              </p>
              <p style={{ display: 'inline-flex', gap: '10px' }}>
                <span>{t('strategicObjectives:columns.measurementTypes')}</span>
                :
                <span>
                  {record.measurementType ==
                    measurementTypeEnum['Increasing Better'] ||
                  record.measurementType ==
                    measurementTypeEnum['Decreasing Better']
                    ? measurementTypesEnum[record.measurementType]
                    : '--'}
                </span>
              </p>
            </div>
          )
        }
      >
        <div>
          <PieChart
            performance={roundDown(progress, true)}
            actualOfDate={actualOfDate}
            measurementMechanism={measurementMechanism}
            unitType={unitType}
            formulas={formulas}
            type={type}
            averageOfDate={averageOfDate}
          />
        </div>
      </Popover>
    )
  }

  const columnsData: TableColumnProps[] = [
    {
      title: t('kpis:list.column.name'),
      dataIndex: 'kpiName',
      width: 310,
      render: (_, record) => {
        return cycleClosed(record?.cycleStatus) ? (
          <div style={{ cursor: 'pointer' }}>
            <Badge
              color={getDaysAgo(record.lastUpdateTime)}
              style={isLanguageAR ? { marginLeft: 6 } : { marginRight: 6 }}
            ></Badge>
            {renderEllipsisText(record.kpiName)}
          </div>
        ) : (
          <div
            onClick={() =>
              jumpToDetailsPage({
                type: 'kpis',
                id: record.kpiInfoId,
                navigate,
                record,
              })
            }
            style={{ cursor: 'pointer' }}
          >
            <Badge
              color={getDaysAgo(record.lastUpdateTime)}
              style={isLanguageAR ? { marginLeft: 6 } : { marginRight: 6 }}
            ></Badge>
            {renderEllipsisText(record.kpiName, underline())}
          </div>
        )
      },
    },
    {
      title: t('milestones:milestonesManagement.completionRate'),
      dataIndex: 'completionOfDate',
      width: 150,
      render: (value, record) => {
        return getProgressDetailRate(record)
      },
    },
    {
      title: t('activities:columns.avtual'),
      dataIndex: 'actualOfDate',
      width: 150,
      render: (value, record) => {
        return renderEllipsisText(+record.actualOfDate.toFixed(2))
      },
    },
    {
      title: t('kpis:list.column.objective'),
      dataIndex: 'objectName',
      width: 150,
      render: renderEllipsisText,
    },
    {
      title: t('kpis:add.type.title'),
      dataIndex: 'type',
      width: 180,
      // render: renderEllipsisText,
      render: (_, record) => {
        return renderEllipsisText(strategyApiTypeObject[record.type])
      },
    },
    {
      title: t('kpis:kpiType'),
      dataIndex: 'kpiType',
      width: 180,
      render: (_, record) => {
        return renderEllipsisText(kpiTypeEnum[record.kpiType])
      },
    },
    {
      title: t('kpis:list.column.responsiblePerson'),
      dataIndex: 'responsiblePersonList',
      width: 200,
      render: renderEllipsisText,
    },
    {
      title: t('historyLog:columns.department'),
      dataIndex: 'orgName',
      width: 180,
      render: (_, record) => {
        const orgName = isLanguageAR
          ? record.orgInfo?.orgNameAr
          : record.orgInfo?.orgName
        return renderEllipsisText(orgName)
      },
    },
    {
      title: t('kpis:list.column.startDate'),
      dataIndex: 'startDate',
      width: 180,
      sorter: function (a, b) {
        let start = dayjs(a.startDate, 'DD/MM/YYYY').valueOf()
        let end = dayjs(b.startDate, 'DD/MM/YYYY').valueOf()
        return start - end
      },
      render: renderEllipsisText,
    },
    {
      title: t('kpis:list.column.endDate'),
      dataIndex: 'endDate',
      width: 180,
      sorter: function (a, b) {
        let start = dayjs(a.endDate, 'DD/MM/YYYY').valueOf()
        let end = dayjs(b.endDate, 'DD/MM/YYYY').valueOf()
        return start - end
      },
      render: renderEllipsisText,
    },
    {
      title: t('kpis:list.column.status'),
      dataIndex: 'status',
      width: 150,
      render: (value) => {
        return (
          <Badge
            color={STATUS_COLOR[value]}
            text={t(
              `project:projectReleaseStatus.${PROJECT_RELEASE_STATUS_TEXTS[value]}`,
            )}
          />
        )
      },
    },
    {
      title: t('kpis:list.column.action.title'),
      dataIndex: 'action',
      fixed: 'right',
      width: 150,
      render: (_, record) => {
        return (
          <RowActionBtns
            cycleStatus={record?.cycleStatus}
            rowData={record}
            isCanActualValue={record.status}
            deleteHandler={() => {
              setCurrentDeleRowId(record.id)
              setDeleteNotificationVisible(true)
            }}
            actualValueHandler={() => {
              setKpiInfoId(record.kpiInfoId)
              setActualValueModalVisible(true)
            }}
          />
        )
      },
    },
  ]

  const removeCycleIdAndYear = () => {
    setKpiSearchInfo({
      ...kpiSearch,
      cycleId: '',
      year: '',
      pageNum: 1,
    })
    setKpiFilterParams({ cycleId: '', year: '', pageNum: 1 })
  }
  const handleSelectChange = (value) => {
    setKpiSearchInfo({
      ...kpiSearch,
      cycleId: value?.[0] || '',
      year: value?.[1] || '',
      orgId: '',
      pageNum: 1,
    })
    setKpiFilterParams({ cycleId: value, orgId: '', pageNum: 1 })
    getOrgTree({ cycleId: value?.[0] })
    tableRef.current?.refresh()
  }

  useEffect(() => {
    setKpiSearchInfo({
      ...kpiSearch,
      userView: isUser,
    })

    setKpiFilterParams({
      userView: isUser,
    })
    tableRef.current?.refresh()
  }, [isUser])

  useEffect(() => {
    tableRef.current?.setPageNum(kpiSearch.pageNum)
  }, [kpiSearch.pageNum])

  //获取department 列表
  const { run: getOrgTree } = useRequest(getOrgTreeRecursion, {
    manual: true,
    onSuccess(res: any, params) {
      formRef?.current?.setFormItemValue('orgId', undefined)
      const data = transformData(res, t)
      setDepartmentData(data || [])
    },
    onError(e, params) {
      console.log({ e, params })
    },
  })
  useEffect(() => {
    getProjectTableConfig(TableBizType.Kpi)
  }, [])

  const departmentNameChange = (value) => {
    setKpiSearchInfo({
      ...kpiSearch,
      orgId: value,
      pageNum: 1,
    })
    setKpiFilterParams({
      orgId: value,
      pageNum: 1,
    })
    tableRef.current?.refresh()
  }

