  const isAcceptFile = (file, accept) => {
    if (accept && file) {
      const fileExtension =
        file.name.indexOf('.') > -1 ? file.name.split('.').pop() : ''
      return fileExtension === accept
    }
    return !!file
  }

  //上传进度
  const updateProgress = (file, percent) => {
    uploadList.forEach((f) => {
      if (_.eq(f.file, file)) {
        f.percent = percent
        f.finish = percent === 100
      }
    })
  }

  // 生成唯一id
  const UniqueId = () => {
    const timePart = new Date().getTime()
    const randomPart = Math.floor(Math.random() * 1000000)
    const uid = Number(`${timePart}${randomPart}`)
    return uid
  }

  const uploadCustomRequest = async (option) => {
    setIsUploading(true)
    const { file } = option
    setUploadList(uploadList.concat([{ file, percent: 0, finish: false }]))
    const config = {
      onUploadProgress: (progressEvent) => {
        if (progressEvent.lengthComputable) {
          const percentCompleted = Math.round(
            (progressEvent.loaded * 100) / progressEvent.total,
          )
          updateProgress(file, percentCompleted)
        }
      },
      cancelToken: new CancelToken((cancel) => {
        cancelUpload = cancel
      }),
    }
    const type = File_UPLOAD_TYPE.KPI_IMPORT
    const uniqueId = UniqueId()
    const uid = Number(
      `${Date.now()}${Math.floor(Math.random() * 90000) + 10000}`,
    )
    const formData: any = new FormData()
    formData.append('file', file)
    formData.append('type', type)
    formData.append('uniqueId', uniqueId)
    formData.append('uid', uid)
    uploadFile(formData, config)
      .then((res: any) => {
        setFileList(fileList.concat([{ ...res }]))
        const uploads = uploadList.filter((f) => !_.eq(f.file, file))
        setUploadList(uploads)
        setIsUploading(false)
      })
      .catch(() => {
        setIsUploading(false)
        const uploads = uploadList.filter((f) => !_.eq(f.file, file))
        setUploadList(uploads)
        formMilestone.resetFields()
      })
  }

