const getTableColumns = (
  t,
  unitType,
  yearlyPerformance,
  tableData,
  measurementMechanism,
  formType,
) => {
  // 根据当前语言与单位类型，统一拼接表格中数值列的后缀
  const isLanguageAR = getLanguage() === LanguageEnum.AR
  const suffixObj = {
    '0': '%',
    '1': 'AED',
    '2': '',
    '3': isLanguageAR ? 'ساعة' : 'hour',
    '4': isLanguageAR ? 'اليوم' : 'days',
  }

  const suffixObj_Ar = {
    '0': '%',
    '1': 'AED',
    '2': '',
    '3': 'ساعة',
    '4': 'اليوم',
  }
  const tableColumns: EditableColumnType[] = [
    {
      title: t('kpis:add.table.column.frequency'),
      editable: false,
      dataIndex: 'measurementName',
    },
    ...(formType == strategyApiTypeEnum['Counted in Stats']
      ? [
          {
            title: t('kpis:add.table.column.target'),
            editable: true,
            dataIndex: 'targetPerformance',
            type: 'number',
            placeholder: t('common:pleaseEnter'),
            suffix: suffixObj[unitType] ?? '',
            rules: [
              measurementMechanism == measurementMechanismEnum['duration']
                ? { required: false }
                : { required: true, message: t('common:pleaseEnter') },
            ],
          },
        ]
      : []),
    {
      title: t('kpis:add.table.column.actual'),
      editable: false,
      dataIndex: 'actualPerformance',
      render: (value, record) => {
        const suffix = suffixObj[unitType] || ''
        if (value) {
          return value + ` ${suffix}`
        } else {
          return suffix ? `-- ${suffix}` : '--'
        }
      },
    },
    {
      title: t('kpis:add.table.column.ratio'),
      editable: false,
      dataIndex: 'periodPerformanceRatio',
      render: (value, record) => {
        if (value) {
          return value + `%`
        } else {
          return <div>{t('milestones:auto')}</div>
        }
      },
    },
    {
      title: t('kpis:add.table.column.status'),
      editable: false,
      dataIndex: 'status',
      render: (value, record) => {
        if (value === null) return <div>{t('milestones:auto')}</div>
        if (value) {
          return <div>{t('milestones:onTime')}</div>
        } else {
          return <div>{t('milestones:delay')}</div>
        }
        // return (
        //   <div style={{ color: '#C9CDD4' }}>{t('kpis:add.table.autoCalc')}</div>
        // )
      },
    },
    {
      title: t('kpis:add.table.column.attachments'),
      editable: false,
      dataIndex: 'attachments',
      render: (value, record) => {
        if (_.isArray(record.attachments) && record.attachments.length > 0) {
          return (
            <div>
              {record.attachments.map((item, index) => {
                return (
                  <div title={item.fileName} key={index}>
                    {truncateString(item.fileName, 15)}
                  </div>
                )
              })}
            </div>
          )
        } else {
          return '--'
        }
        // return <div style={{ color: '#C9CDD4' }}>--</div>
      },
    },
    {
      title: t('kpis:add.table.column.yearlyPerformance'),
      width: 210,
      editable: false,
      dataIndex: 'yearlyPerformance',
      // colSpan: 2,
      render: (col, item, index) => {
        const result = yearlyPerformance ? (
          `${yearlyPerformance}%`
        ) : (
          <span style={{ color: '#C9CDD4' }}>{t('milestones:auto')}</span>
        )
        const obj = {
          children: result,
          props: {
            rowSpan: 0,
          },
        }
        if (index === 0) {
          obj.props.rowSpan = tableData?.length
        }
        if (index === 1 || index === 2) {
          obj.props.rowSpan = 0
        }
        return obj
      },
    },
  ]
  return tableColumns
}
