const GeneralInfoAi = ({
  form,
  measurementTable,
  tableRef,
  setMeasurementTable,
}: GeneralInfoAiProps) => {
  const { t } = isReadServerTextData
    ? useLocaleTranslation()
    : useTranslation(['common', 'project', 'activities', 'kpis'])
  const location = useLocation()
  const { type, kpiType } = location.state || {}

  const { MONTH_ENUM } = useCodeEnums()
  const isLanguageAR = getLanguage() === LanguageEnum.AR
  // const tableRef = useRef<EditableRef>(null)
  const formMeasCycle = Form.useWatch('measurementCycle', form)
  const formStartDate = Form.useWatch('startDate', form)
  const formEndDate = Form.useWatch('endDate', form)
  const formMechanism = Form.useWatch('measurementMechanism', form)
  const formulasWatch = Form.useWatch('formulas', form)
  const measurementUnit = Form.useWatch('measurementUnit', form)

  const [disableUnit, setDisableUnit] = useState(false)
  const [disableMeasurementType, setDisableMeasurementType] = useState(false)
  const [disableAssemblyMethod, setDisableAssemblyMethod] = useState(false)

  const [tableData, setTableData] = useState<any[]>([])

  ///
  const [currentUnit, setCurrentUnit] = useState()
  const [yearlyPerformance, setYearlyPerformance] = useState('--')
  const [measurementMechanism, setMeasurementMechanism] = useState<any>()
  const [formType, setFormType] = useState<any>()

  // measurementCycleOptions setting
  const measurementCycleOptionsData = useMemo(() => {
    const baseOptions = [
      {
        label: t('kpis:informationTypes.annual'),
        value: measurementCycleEnum.Annual,
      },
      {
        label: t('kpis:informationTypes.semiannual'),
        value: measurementCycleEnum.Semiannual,
      },
      {
        label: t('kpis:informationTypes.quarter'),
        value: measurementCycleEnum.Quarter,
      },
    ]
    if (
      kpiType === kpiTypeEnum.operationalKpi ||
      kpiType === kpiTypeEnum.processKpi
    ) {
      return [
        ...baseOptions,
        {
          label: t('milestones:monthly'),
          value: measurementCycleEnum.Monthly,
        },
      ]
    }

    if (
      (kpiType === kpiTypeEnum.strategicKpi ||
        kpiType === kpiTypeEnum.enablerKpi) &&
      formMeasCycle === measurementCycleEnum.Monthly
    ) {
      form.setFieldValue('measurementCycle', undefined)
    }
    return baseOptions
  }, [t, kpiType])

  const measurementTypeOptions = useMemo(
    () => [
      {
        label: t('kpis:informationTypes.increasingBetter'),
        value: measurementTypeEnum['Increasing Better'],
      },
      {
        label: t('kpis:informationTypes.decreasingBetter'),
        value: measurementTypeEnum['Decreasing Better'],
      },
    ],
    [t],
  )

  const assemblyMethodOptions = useMemo(
    () => [
      {
        label: t('kpis:informationTypes.sum'),
        value: assemblyMethodEnum.Sum,
      },
      {
        label: t('kpis:informationTypes.average'),
        value: assemblyMethodEnum.Average,
      },
      {
        label: t('kpis:informationTypes.lastValue'),
        value: assemblyMethodEnum.LastValue,
      },
    ],
    [t],
  )

  const measurementMechanismOptions = useMemo(
    () => [
      {
        label: t('kpis:informationTypes.withFormula'),
        value: measurementMechanismEnum['with formula'],
      },
      {
        label: t('kpis:informationTypes.withoutFormula'),
        value: measurementMechanismEnum['without formula'],
      },
    ],
    [t],
  )

  const formulasOptions = useMemo(
    () => [
      {
        label: t('formula:formulaDataTitle.growthRate'),
        value: formulasEnum.GrowthRate,
      },
      {
        label: t('formula:formulaDataTitle.division'),
        value: formulasEnum.Division,
      },
      {
        label: t('formula:formulaDataTitle.sum'),
        value: formulasEnum.Sum,
      },
      {
        label: t('formula:formulaDataTitle.average'),
        value: formulasEnum.Average,
      },
      {
        label: t('project:projectDeleteInfo.duration'),
        value: formulasEnum.Duration,
      },
    ],
    [t],
  )

  const measurementUnitOptions = useMemo(
    () => [
      {
        label: t('kpis:informationTypes.percentage'),
        value: measurementUnitEnum.Percentage,
      },
      {
        label: t('kpis:informationTypes.currency'),
        value: measurementUnitEnum.Currency,
      },
      {
        label: t('kpis:informationTypes.number'),
        value: measurementUnitEnum.Number,
      },
      {
        label: t('kpis:informationTypes.hour'),
        value: measurementUnitEnum.Hour,
      },
      {
        label: t('kpis:informationTypes.day'),
        value: measurementUnitEnum.Day,
      },
    ],
    [t],
  )

  const yearStr = useMemo(
    () => ({
      Q1: t('kpis:year.Q1'),
      Q2: t('kpis:year.Q2'),
      Q3: t('kpis:year.Q3'),
      Q4: t('kpis:year.Q4'),
      H1: t('kpis:year.Q2'),
      H2: t('kpis:year.Q4'),
      ANNUAL: t('kpis:year.Q4'),
    }),
    [t],
  )

  useEffect(() => {
    setFormType(type)
  }, [])

  const targetSuffix = useMemo(() => {
    const suffixObj: Record<string, string> = {
      '0': '%',
      '1': 'AED',
      '2': '',
      '3': isLanguageAR ? 'ساعة' : 'hour',
      '4': isLanguageAR ? 'اليوم' : 'days',
    }
    return suffixObj[String(measurementUnit ?? '')] ?? ''
  }, [measurementUnit, isLanguageAR])

  const generateTableData = (
    keys: string[],
    endDate: any,
    isYear = false,
    isMonth = false,
    measurementTable?: any[]
  ) =>
    keys.map((key) => {
      const target = measurementTable?.find(( item ) => item.key === key)?.targetPerformance || ''
      return {
      key,
      measurementName: `${isYear ? t('kpis:year.Q4') : isMonth ? MONTH_ENUM[key] : yearStr[key]} ${dayjs(endDate).year()}`,
      targetPerformance: target,
      actualPerformance: null,
      periodPerformanceRatio: '',
      status: null as null,
      attachments: '--',
    }})

  const safeSetTableData = (nextData: any[]) => {
    setTableData((prev) => (_.isEqual(prev, nextData) ? prev : nextData))
  }

  // 记录上一次写入 measurementTable 的数据快照，避免数据未变化时重复调用导致无限循环
  const prevMeasurementTableJsonRef = useRef<string>('')
  const safeSetMeasurementTable = (nextData: any[]) => {
    const nextJson = JSON.stringify(nextData)
    if (prevMeasurementTableJsonRef.current !== nextJson) {
      prevMeasurementTableJsonRef.current = nextJson
      setMeasurementTable(nextData)
    }
  }

  // 用 ref 实时跟踪 measurementTable 最新值，避免 effect closure 中拿到过期快照
  // 在 render 阶段同步更新（而非 useEffect），确保后续 effect 执行时 ref 已是最新值，
  // 避免因 measurementTable 与表单值在不同 render 批次中更新而导致缓存命中失败
  const measurementTableRef = useRef<any[]>(measurementTable ?? [])
  measurementTableRef.current = measurementTable ?? []

  // 按”周期+起止日期”缓存各周期的表格数据，切换回原周期时可恢复
  const cachedTableDataRef = useRef<Record<string, any[]>>({})
  const prevCycleKeyRef = useRef<string>('')

  // 根据”统计周期 + 起止日期”动态生成表格行数据。
  // 这个 effect 的作用是：当用户修改周期或日期时，立即重算每一行频次（年/半年/季度/月）。
  useEffect(() => {
    const currentKey = `${formMeasCycle}-${formStartDate}-${formEndDate}`

    // 前置条件不完整时，清空表格，避免展示过期数据。
    if (
      formMeasCycle === undefined ||
      formMeasCycle === null ||
      !formStartDate ||
      !formEndDate
    ) {
      if (prevCycleKeyRef.current) {
        cachedTableDataRef.current[prevCycleKeyRef.current] =
          measurementTableRef.current
        prevCycleKeyRef.current = ''
      }
      safeSetTableData([])
      return
    }

    // 切走前把当前数据存入缓存
    if (prevCycleKeyRef.current && prevCycleKeyRef.current !== currentKey) {
      cachedTableDataRef.current[prevCycleKeyRef.current] =
        measurementTableRef.current
    }
    // 仅组件挂载时（prevKey 为空），若 measurementTable 已有数据（如编辑回填），先缓存起来
    // 切换周期时不走这里，避免把旧周期数据错误缓存到新 key 下
    if (
      !prevCycleKeyRef.current &&
      !cachedTableDataRef.current[currentKey] &&
      measurementTableRef.current?.length > 0
    ) {
      cachedTableDataRef.current[currentKey] = measurementTableRef.current
    }
    prevCycleKeyRef.current = currentKey

    // 有缓存则直接恢复，不重新生成空白数据
    if (cachedTableDataRef.current[currentKey]?.length > 0) {
      const cached = cachedTableDataRef.current[currentKey]
      safeSetTableData(cached)
      safeSetMeasurementTable(cached)
      return
    }

    try {
      // keys 表示每一行对应的周期标识（如 ANNUAL / H1 / Q2 / jan 等）。
      let keys: string[]
      let isYear = false
      let isMonth = false
      const end = formEndDate
      // 按不同统计周期，生成对应的 keys 列表。
      if (formMeasCycle === measurementCycleEnum.Annual) {
        keys = [yearCode]
        isYear = true
      } else if (formMeasCycle === measurementCycleEnum.Semiannual) {
        keys = calculateHalfYears(formStartDate, formEndDate).map((item) =>
          yearQuarterSwitch(formMeasCycle, item),
        )
      } else if (formMeasCycle === measurementCycleEnum.Quarter) {
        keys = getQuartersBetweenDates(formStartDate, formEndDate)
      } else if (formMeasCycle === measurementCycleEnum.Monthly) {
        keys = getMonthsBetweenMonths(formStartDate, formEndDate)
        isMonth = true
      } else {
        // 未识别的周期类型：兜底清空，避免异常数据进入表格。
        safeSetTableData([])
        return
      }
      // 统一根据 keys 生成表格结构（频次名、目标值、实际值等默认字段）。
      const newData = generateTableData(keys, end, isYear, isMonth, measurementTable)
      console.log('newData', newData)
      safeSetTableData(newData)
      safeSetMeasurementTable(newData)
    } catch {
      // 日期或周期计算异常时兜底清空，避免页面报错。
      safeSetTableData([])
    }
  }, [formMeasCycle, formStartDate, formEndDate, t, yearStr])

  // 选择“without formula”时清空公式字段，避免保留无效值提交
  useEffect(() => {
    if (formMechanism === measurementMechanismEnum['without formula']) {
      form.setFieldValue('formulas', undefined)
    }
  }, [formMechanism, form])

  //// Duration 公式有固定业务规则：单位=小时、类型=越小越好、汇总=平均，并锁定对应控件
  useEffect(() => {
    if (formulasWatch === formulasEnum.Duration) {
      form.setFieldValue('measurementUnit', measurementUnitEnum.Hour)
      form.setFieldValue(
        'measurementType',
        measurementTypeEnum['Decreasing Better'],
      )
      form.setFieldValue('assemblyMethod', assemblyMethodEnum.Average)
      setDisableUnit(true)
      setDisableMeasurementType(true)
      setDisableAssemblyMethod(true)
    } else {
      setDisableUnit(false)
      setDisableMeasurementType(false)
      setDisableAssemblyMethod(false)
    }
  }, [formulasWatch, form])

  const cycleAndDatesReady = !!(formStartDate && formEndDate)
  const showFormulas = !formMechanism

  return (
    <div className='generalInfoAi'>
      {/* 第一行 */}
      <Row gutter={40}>
        <Col span={12}>
          <FormItem
            label={t('kpis:add.kpiNameEn')}
            field={'kpiName'}
            rules={[{ required: true, message: t('common:pleaseEnter') }]}
          >
            <Input
              maxLength={MaxLengthEnum.Input}
              placeholder={t('login:information.common.pleaseEnter')}
            />
          </FormItem>
        </Col>
        <Col span={12}>
          <FormItem
            label={t('kpis:add.kpiNameAr')}
            field={'kpiNameAr'}
            rules={[{ required: true, message: t('common:pleaseEnter') }]}
          >
            <Input
              maxLength={MaxLengthEnum.Input}
