import { useEffect, useState, useRef } from 'react'
import { Form, Button, Modal } from '@arco-design/web-react'
import { isReadServerTextData } from '@common/constants/env'
import useLocaleTranslation from '@common/hooks/useLocaleTranslation'
import { useTranslation } from 'react-i18next'
import AddProjectUpload from '@common/components/AddProjectUpload'
import GeneralInfoAi from '../GeneralInfoAi'
import ProjectAiRegenerateIcon from '@/assets/images/icon/projectAiRegenerate-icon.svg?react'
import { useRequest } from 'ahooks'
import { useNavigate, useParams, useLocation } from 'react-router-dom'
import { kpiRegenerateAi, kpiPublishAi } from '@/service'
import { useCodeEnums } from '@common/hooks/useCodeEnums'
import dayjs from 'dayjs'
import EditableTable, {
  EditableRef,
} from '@/pages/StrategyCycle/components/EditableTable/EditableTable.tsx'
import {
  GenerationType,
  kpiTypeEnum,
  strategyApiTypeEnum,
} from '@/constants/strategicKpis'
import './index.less'

type Props = {
  visible?: any
  setVisible?: any
  generalInfo?: any
  TableData?: any
  setGeneralInfo?: any
  setMeasurementTable?: any
  setTableData?: any
}
const RegenerateModal = ({
  visible,
  setVisible,
  generalInfo,
  setGeneralInfo,
  setTableData,
}: Props) => {
  const { t } = isReadServerTextData
    ? useLocaleTranslation()
    : useTranslation(['common', 'project', 'activities'])
  const [regenerateForm] = Form.useForm()
  //////////////////////////////  project upload  ///////////////
  const [fileList, setFileList] = useState<any>([])
  const [allUserIntent, setAllUserIntent] = useState<any>()
  const location = useLocation()
  const { MONTH_ENUM } = useCodeEnums()
  const {
    objectiveId,
    cycleId,
    pillarId,
    orgId,
    type,
    kpiType,
    generationType,
  } = location.state || {}
  const [regenerateTable, setRegenerateTable] = useState<any>()
  const [regenerateInfo, setRegenerateInfo] = useState<any>()
  const tableRef = useRef<EditableRef>(null)
  const isAiRef = useRef(false)
  const endYearDate = Form.useWatch('endDate', regenerateForm)
  // 提取公共的表格行数据生成函数
  /**
   * 需求OPAB-561提出
   * ● 将“半年度”H1改为Q2，H2改为Q4。
   * ● 将“年度”改为Q4。
   */
  const yearStr = {
    Q1: t('kpis:year.Q1'),
    Q2: t('kpis:year.Q2'),
    Q3: t('kpis:year.Q3'),
    Q4: t('kpis:year.Q4'),
    H1: t('kpis:year.Q2'),
    H2: t('kpis:year.Q4'),
    ANNUAL: t('kpis:year.Q4'),
  }

  const getMeasurementName = (
    key,
    endDate,
    isYear = false,
    isMonth = false,
  ) => {
    const measurementName = `${isYear ? t('kpis:year.Q4') : isMonth ? MONTH_ENUM[key] : yearStr[key]} ${dayjs(endDate).year()}`
    return measurementName
  }

  useEffect(() => {
    const info = regenerateInfo ? regenerateInfo?.[0] : generalInfo?.[0]
    const parseDate = (val: any) =>
      typeof val === 'string' && val.includes('/')
        ? val.split('/').reverse().join('-')
        : dayjs(val).isValid()
          ? dayjs(val).format('YYYY-MM-DD')
          : undefined
    regenerateForm.setFieldsValue({
      ...info,
      startDate: parseDate(info?.startDate),
      endDate: parseDate(info?.endDate),
    })
    const tableData = info?.measurementCycleData?.map((item) => {
      return {
        ...item,
        // measurementName: getMeasurementName(item?.code, endYearDate),
        key: item?.code,
        measurementName: getMeasurementName(
          item?.code,
          parseDate(info?.endDate),
        ),
      }
    })
    isAiRef.current = false
    setRegenerateTable(tableData)
  }, [regenerateInfo, generalInfo, endYearDate])

  //再次生成
  const { run: runKpiRegenerateAi, loading: kpiRegenerateAiLoading } =
    useRequest(kpiRegenerateAi, {
      manual: true,
      onSuccess: (res: any) => {
        isAiRef.current = true
        setRegenerateInfo(res)
      },
    })
  ///Ai 生成
  const handelFileListSend = () => {
    const generalInfoData = regenerateForm.getFieldsValue()
    const aiUploadData = {
      userIntent: allUserIntent,
      objectiveId: objectiveId,
      orgId: orgId,
      kpiType: kpiType,
      generationType: generationType,
      attachmentList: fileList,
      historyList: [
        {
          ...generalInfoData,
        },
      ],
    }
    runKpiRegenerateAi(aiUploadData)
  }

  const handelPublish = () => {
    const tableRefData = tableRef.current.getData()
    const data = regenerateForm.getFieldsValue()
    let params = null
    if (generationType == GenerationType.Multi) {
      params = [
        {
          ...data,
          measurementCycleData: tableRefData,
          isModal: true,
          id: generalInfo?.[0]?.id,
        },
      ]
    } else {
      params = [
        {
          ...data,
          measurementCycleData: tableRefData,
          isModal: true,
        },
      ]
    }
    setGeneralInfo(params)
    setVisible(false)
    regenerateForm.clearFields()
  }
  const closeModal = () => {
    setVisible(false)
    regenerateForm.clearFields()
    setAllUserIntent(null)
    setFileList(null)
    // setMeasurementTable(null)
  }
  return (
    <Modal
      visible={visible}
      style={{ width: 1020 }}
      autoFocus={false}
      focusLock={true}
      onOk={() => handelPublish()}
      okText={t('common:btn.save')}
      cancelText={t('common:btn.cancel')}
      onCancel={closeModal}
      title={t('kpis:edit.title')}
    >
      <div className='RegenerateModal'>
        <div className='RegenerateModal-addProjectUpload'>
          <AddProjectUpload
            fileList={fileList}
            setFileList={setFileList}
            handelFileListSend={handelFileListSend}
            userIntent={allUserIntent}
            setUserIntent={setAllUserIntent}
            loading={kpiRegenerateAiLoading}
          />
        </div>
        <Form
          form={regenerateForm}
          layout='vertical'
          autoComplete='off'
          className='addKpiForm'
        >
          <div className='RegenerateModal-generalInfo'>
            <GeneralInfoAi
              key={generalInfo?.[0]?.id}
              form={regenerateForm}
              measurementTable={regenerateTable}
              tableRef={tableRef}
              setMeasurementTable={setRegenerateTable}
            />
          </div>
        </Form>
      </div>
    </Modal>
  )
}
export default RegenerateModal

import { useState } from 'react'
import { Select, Tree } from '@arco-design/web-react'
import { useTranslation } from 'react-i18next'
import useLocaleTranslation from '@common/hooks/useLocaleTranslation'
import { isReadServerTextData } from '@common/constants/env'
import { FC } from 'react'

interface SelectTreeProps {
  treeData: any
  onChange: any
  options: any
  expandedAllKeys: any
  selectObjectiveId: string | number
  isAdminPublishedEdit?: boolean
}
const SelectTree: FC<SelectTreeProps> = ({
  treeData,
  onChange,
  options,
  expandedAllKeys,
  selectObjectiveId,
  isAdminPublishedEdit,
}) => {
  const { t } = isReadServerTextData
    ? useLocaleTranslation()
    : useTranslation('common')
  const [visible, setVisible] = useState(false)
  const [selectedKey, setSelectedKey] = useState(selectObjectiveId)
  const handleTreeSelect = (keys, info) => {
    setSelectedKey(info.node.key)
    setVisible(false)
    if (onChange) {
      onChange(keys[0], info['node']['props']['pathParentKeys'][0])
    }
  }
  const handleVisibleChange = (newVisible) => {
    setVisible(newVisible)
  }

  return (
    <Select
      style={{ width: '100%' }}
      placeholder={t('common:pleaseSelect')}
      value={selectedKey}
      options={options}
      disabled={isAdminPublishedEdit}
      getPopupContainer={(triggerNode) =>
        triggerNode.closest('div') as HTMLElement
      }
      popupVisible={visible}
      dropdownRender={() => {
        return (
          <Tree
            style={{ height: '300px', overflowY: 'auto' }}
            onSelect={handleTreeSelect}
            treeData={treeData}
            defaultExpandedKeys={expandedAllKeys}
            defaultSelectedKeys={expandedAllKeys}
          />
        )
      }}
      onVisibleChange={handleVisibleChange} // 确保下拉菜单的可见性状态同步
    />
  )
}

export default SelectTree

// 根据”统计周期 + 起止日期”动态生成表格行数据。
// 这个 effect 的作用是：当用户修改周期或日期时，立即重算每一行频次（年/半年/季度/月）。
useEffect(() => {
  const currentKey = `${formMeasCycle}-${formStartDate}-${formEndDate}`
  // 记录本次是否为首次挂载（prevCycleKeyRef 为空），用于下方判断是否回写父组件
  const isFirstRun = !prevCycleKeyRef.current

  // 前置条件不完整时，清空表格，避免展示过期数据。
  if (
    formMeasCycle === undefined ||
    formMeasCycle === null ||
    !formStartDate ||
    !formEndDate
  ) {
    if (prevCycleKeyRef.current) {
      cachedTableDataRef.current[prevCycleKeyRef.current] =
        measurementTableRef.current
      prevCycleKeyRef.current = ''
    }
    safeSetTableData([])
    return
  }

  // 切走前把当前数据存入缓存
  if (prevCycleKeyRef.current && prevCycleKeyRef.current !== currentKey) {
    cachedTableDataRef.current[prevCycleKeyRef.current] =
      measurementTableRef.current
  }
  // 仅组件挂载时（prevKey 为空），若 measurementTable 已有数据（如编辑回填），先缓存起来
  // 切换周期时不走这里，避免把旧周期数据错误缓存到新 key 下
  if (
    !prevCycleKeyRef.current &&
    !cachedTableDataRef.current[currentKey] &&
    measurementTableRef.current?.length > 0
  ) {
    cachedTableDataRef.current[currentKey] = measurementTableRef.current
  }
  prevCycleKeyRef.current = currentKey

  // 有缓存则直接恢复，不重新生成空白数据
  if (cachedTableDataRef.current[currentKey]?.length > 0) {
    const cached = cachedTableDataRef.current[currentKey]
    safeSetTableData(cached)
    safeSetMeasurementTable(cached)
    return
  }

  try {
    // keys 表示每一行对应的周期标识（如 ANNUAL / H1 / Q2 / jan 等）。
    let keys: string[]
    let isYear = false
    let isMonth = false
    const end = formEndDate
    // 按不同统计周期，生成对应的 keys 列表。
    if (formMeasCycle === measurementCycleEnum.Annual) {
      keys = [yearCode]
      isYear = true
    } else if (formMeasCycle === measurementCycleEnum.Semiannual) {
      keys = calculateHalfYears(formStartDate, formEndDate).map((item) =>
        yearQuarterSwitch(formMeasCycle, item),
      )
    } else if (formMeasCycle === measurementCycleEnum.Quarter) {
      keys = getQuartersBetweenDates(formStartDate, formEndDate)
    } else if (formMeasCycle === measurementCycleEnum.Monthly) {
      keys = getMonthsBetweenMonths(formStartDate, formEndDate)
      isMonth = true
    } else {
      // 未识别的周期类型：兜底清空，避免异常数据进入表格。
      safeSetTableData([])
      return
    }
    // 统一根据 keys 生成表格结构（频次名、目标值、实际值等默认字段）。
    const newData = generateTableData(keys, end, isYear, isMonth, measurementTable)
    console.log('newData', newData)
    safeSetTableData(newData)
    safeSetMeasurementTable(newData)
  } catch {
    // 日期或周期计算异常时兜底清空，避免页面报错。
    safeSetTableData([])

